import React, { useState, useEffect } from 'react';
import api from '../lib/api';

const Dashboard = () => {
  const [stats, setStats] = useState({
    totalDevices: 0,
    activeDevices: 0,
    inactiveDevices: 0,
    totalBackups: 0
  });
  const [devices, setDevices] = useState([]);
  const [loading, setLoading] = useState(true);
  const [recentLogs, setRecentLogs] = useState([]);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      // Carregar dispositivos
      const devicesRes = await api.get('/devices/');
      const deviceList = devicesRes.data.results || devicesRes.data || [];
      setDevices(deviceList);

      // Calcular estatísticas
      const active = deviceList.filter(d => d.is_active !== false).length;
      const inactive = deviceList.filter(d => d.is_active === false).length;

      setStats({
        totalDevices: deviceList.length,
        activeDevices: active,
        inactiveDevices: inactive,
        totalBackups: 0
      });

      // Carregar logs de auditoria
      try {
        const logsRes = await api.get('/audit-logs/');
        setRecentLogs(logsRes.data.results || logsRes.data || []);
      } catch (e) {
        console.log('Audit logs not available');
      }

    } catch (error) {
      console.error('Error loading data:', error);
    } finally {
      setLoading(false);
    }
  };

  const statCards = [
    { label: 'Total de Dispositivos', value: stats.totalDevices, icon: '🖥️', color: 'bg-blue-600', change: '+2' },
    { label: 'Dispositivos Ativos', value: stats.activeDevices, icon: '✅', color: 'bg-green-600', change: '' },
    { label: 'Dispositivos Inativos', value: stats.inactiveDevices, icon: '⚠️', color: 'bg-yellow-600', change: '' },
    { label: 'Backups Realizados', value: stats.totalBackups, icon: '💾', color: 'bg-purple-600', change: '+5' },
  ];

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {statCards.map((stat, index) => (
          <div key={index} className="bg-gray-800 rounded-lg p-6 border border-gray-700 hover:border-gray-600 transition">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-gray-400 text-sm">{stat.label}</p>
                <div className="flex items-baseline mt-2">
                  <p className="text-3xl font-bold text-white">{stat.value}</p>
                  {stat.change && (
                    <span className="ml-2 text-green-400 text-sm">{stat.change}</span>
                  )}
                </div>
              </div>
              <div className={`w-14 h-14 ${stat.color} rounded-xl flex items-center justify-center shadow-lg`}>
                <span className="text-2xl">{stat.icon}</span>
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Recent Devices */}
        <div className="bg-gray-800 rounded-lg p-6 border border-gray-700">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-lg font-semibold text-white">Dispositivos Recentes</h2>
            <span className="text-sm text-gray-400">{devices.length} total</span>
          </div>

          {devices.length === 0 ? (
            <div className="text-center py-8">
              <span className="text-4xl mb-2 block">🖥️</span>
              <p className="text-gray-400">Nenhum dispositivo cadastrado</p>
              <p className="text-gray-500 text-sm mt-1">Adicione dispositivos no Inventário</p>
            </div>
          ) : (
            <div className="space-y-3">
              {devices.slice(0, 5).map((device, index) => (
                <div key={device.id || index} className="flex items-center justify-between p-3 bg-gray-700/50 rounded-lg hover:bg-gray-700 transition">
                  <div className="flex items-center space-x-3">
                    <div className={`w-2 h-2 rounded-full ${device.is_active !== false ? 'bg-green-500' : 'bg-red-500'}`}></div>
                    <div>
                      <p className="text-white font-medium">{device.name || device.hostname || 'Sem nome'}</p>
                      <p className="text-gray-400 text-sm">{device.ip || device.ip_address || '-'}</p>
                    </div>
                  </div>
                  <span className="text-gray-400 text-sm">{device.device_type || device.type || 'N/A'}</span>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Recent Activity */}
        <div className="bg-gray-800 rounded-lg p-6 border border-gray-700">
          <h2 className="text-lg font-semibold text-white mb-4">Atividade Recente</h2>

          {recentLogs.length === 0 ? (
            <div className="text-center py-8">
              <span className="text-4xl mb-2 block">📋</span>
              <p className="text-gray-400">Nenhuma atividade recente</p>
            </div>
          ) : (
            <div className="space-y-3">
              {recentLogs.slice(0, 5).map((log, index) => (
                <div key={log.id || index} className="flex items-center space-x-3 p-3 bg-gray-700/50 rounded-lg">
                  <div className="w-8 h-8 bg-blue-600/20 rounded-full flex items-center justify-center">
                    <span className="text-blue-400 text-sm">📝</span>
                  </div>
                  <div className="flex-1">
                    <p className="text-white text-sm">{log.action || 'Ação'}</p>
                    <p className="text-gray-500 text-xs">{log.timestamp || log.created_at || '-'}</p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Device Types Chart */}
      <div className="bg-gray-800 rounded-lg p-6 border border-gray-700">
        <h2 className="text-lg font-semibold text-white mb-4">Distribuição por Tipo</h2>
        <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4">
          {['Router', 'Switch', 'Firewall', 'Server', 'OLT', 'Outro'].map((type) => {
            const count = devices.filter(d => 
              (d.device_type || d.type || '').toLowerCase() === type.toLowerCase()
            ).length;
            const percentage = devices.length > 0 ? Math.round((count / devices.length) * 100) : 0;

            return (
              <div key={type} className="bg-gray-700/50 rounded-lg p-4 text-center">
                <div className="text-2xl font-bold text-white">{count}</div>
                <div className="text-gray-400 text-sm">{type}</div>
                <div className="mt-2 h-1 bg-gray-600 rounded-full overflow-hidden">
                  <div className="h-full bg-blue-500" style={{ width: `${percentage}%` }}></div>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Quick Actions */}
      <div className="bg-gray-800 rounded-lg p-6 border border-gray-700">
        <h2 className="text-lg font-semibold text-white mb-4">Ações Rápidas</h2>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          <button className="p-4 bg-blue-600 hover:bg-blue-500 rounded-lg text-center transition group">
            <span className="text-2xl block mb-2 group-hover:scale-110 transition">➕</span>
            <span className="text-white text-sm font-medium">Novo Dispositivo</span>
          </button>
          <button className="p-4 bg-green-600 hover:bg-green-500 rounded-lg text-center transition group">
            <span className="text-2xl block mb-2 group-hover:scale-110 transition">🔄</span>
            <span className="text-white text-sm font-medium">Sincronizar Tudo</span>
          </button>
          <button className="p-4 bg-purple-600 hover:bg-purple-500 rounded-lg text-center transition group">
            <span className="text-2xl block mb-2 group-hover:scale-110 transition">💾</span>
            <span className="text-white text-sm font-medium">Backup Completo</span>
          </button>
          <button className="p-4 bg-orange-600 hover:bg-orange-500 rounded-lg text-center transition group">
            <span className="text-2xl block mb-2 group-hover:scale-110 transition">📊</span>
            <span className="text-white text-sm font-medium">Gerar Relatório</span>
          </button>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
